#!/usr/bin/env bash
# setup-stop-loss.sh — 技术分析工作流（扫 setup → 入场 → stop-loss → 风险定仓 → 出场 → 复盘） SOP walkthrough for 个人投资理财.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="个人投资理财"
WORKFLOW="技术分析工作流（扫 setup → 入场 → stop-loss → 风险定仓 → 出场 → 复盘）"

usage() {
  cat <<EOF
setup-stop-loss.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./setup-stop-loss.sh             # interactive
  ./setup-stop-loss.sh --dry-run
  ./setup-stop-loss.sh --json
  ./setup-stop-loss.sh --explain
  ./setup-stop-loss.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "技术分析工作流（扫 setup → 入场 → stop-loss → 风险定仓 → 出场 → 复盘）" 工作流。

一句话: 从「我想靠价格图表/形态/动量做短中期择时交易」到「一套有明确入场信号、事前止损、按风险定仓、机械出场的可复盘交易系统」—— 与价值（看基本面）/被动（择时无效）三方互掐。本派信条：价格已含全部信息，可由形态/趋势/动量读出群体行为。(evidence: [T03-S021])

入门 SOP 共 6 步, 失败模式自检 5 项。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**扫 setup（趋势 / 形态 / 动量）**：用扫描器找符合预设的标的——趋势方向（200/50 日 MA）、经典形态（头肩/双底/三角形）、动量强弱、或 CANSLIM 多条件命中（突破基底）。(evidence: [T03-S021])"
  "**定入场（trigger）**：等价格**放量突破**关键阻力/形态边界再进，区分真假突破（need 放量确认 + 防回踩）。"
  "**设 stop-loss（事前）**：**入场前**就定好「跌到哪我认错出场」的价格（技术派风控核心纪律，机械执行非情绪反应）。"
  "**按风险定仓位 (position sizing)**：由「入场价 − 止损价」的距离 + 单笔最大可亏比例（如总资金 1%）**反推**买多少股，让每笔风险敞口一致。趋势/交易派认为 sizing 比选标的更决定长期存活。"
  "**管理出场**：盈利单按规则推移止损（trailing stop）让利润奔跑 / 到目标位减仓；亏损单触止损无条件出。"
  "**复盘（交易日志）**：记录每笔的理由/结果，统计胜率×盈亏比，迭代系统、剔除无效 setup。"
)
declare -a FAILURE_MODES=(
  "**不设止损死扛**：一笔失控亏损吃掉数十笔盈利。自检：这笔交易的止损价是不是入场前就定好了？"
  "**梭哈/固定金额不按风险定仓**：止损宽的标的实际风险爆表。自检：你是按「单笔最多亏 X%」反推的股数吗？"
  "**把技术止损混用到长期价值/被动持仓**：会在最该买时被止损扫出（两套体系混用是新手通病，→ T06 stop-loss tell）。自检：你这笔是「交易」还是「长期投资」，用对体系了吗？"
  "**过拟合回测曲线**：Pine 策略在历史上调参到漂亮曲线、样本外失效（→ T02 反模式）。自检：这个系统在样本外/不同时段还成立吗？"
  "**指标堆砌 + 不复盘**：十个指标互相打架，且从不统计期望。自检：你有交易日志和胜率×盈亏比的真实统计吗？"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "setup-stop-loss-walkthrough"
fi
